[SRSReportParameterAttribute(classStr(ETGCocoashipmentContract))]
class ETGCocoaShipmetDataProvider extends  SRSReportDataProviderPreProcessTempDB

{
    ETGCocoaShipmentTmp                     ETGCocoaShipmentTmp;
    TransDate                               _fromDate,_ToDate;
    List                                    _InvoiceId= new List(Types::String);
    List                                    _ItemId= new List(Types::String);
    List                                    _CustAccount= new List(Types::String);
    CustInvoiceJour                         _CustInvoiceJour;
    CustInvoiceTrans                        _CustInvoiceTrans;
    ETGSalesShipmentCocoa                   _ETGSalesShipmentCocoa;

}

