[SrsReportDataSetAttribute(tableStr(ETGCocoaShipmentTmp))]
public ETGCocoaShipmentTmp getETGCocoaShipmentTmp()
{
    select * from ETGCocoaShipmentTmp;
    return ETGCocoaShipmentTmp;
}

public void ProcessReport()
{
    Query                               query;
    QueryRun                            queryRun;
    QueryBuildDataSource                queryBuildDataSource, queryBuildDataSource1;
    QueryBuildDataSource                queryBuildDataSource2;
    QueryBuildRange                     queryBuildRange;
    QueryBuildRange                     queryBuildRange2;

    ETGCocoashipmentContract   Contract;

    Contract        = this.parmDataContract();

    _fromDate       = Contract.parmFromDate();
    _ToDate         = Contract.parmToDate();
    _CustAccount    = Contract.parmCustAccount();
    _InvoiceId      = Contract.parmInvoiceId();
    _ItemId         = contract.parmItemId();
    ListIterator             ItemIdListIterator,journalIdListIterator;
    ListEnumerator           ListEnumerator;

    query   =   new query();
    queryBuildDataSource    =   query.addDataSource(tableNum(CustInvoiceJour));
    queryBuildDataSource1   =   queryBuildDataSource.addDataSource(tableNum(CustInvoiceTrans));
    queryBuildDataSource1.addLink(fieldNum(CustInvoiceJour,InvoiceId),fieldNum(CustInvoiceTrans,InvoiceId));
    if(_fromDate && !_ToDate)
    {
        queryBuildRange = queryBuildDataSource.addRange(fieldNum(CustInvoiceJour,INVOICEDATE));
        queryBuildRange.value(strFmt('>%1',queryvalue(_fromDate-1)));
    }
    if(!_fromDate && _ToDate)
    {
        queryBuildDataSource.addRange(fieldNum(CustInvoiceJour,INVOICEDATE)).value(strFmt("<%1",queryValue(_ToDate+1)));
    }
    if(_fromDate && _ToDate)
    {
        queryBuildDataSource.addRange(fieldNum(CustInvoiceJour,INVOICEDATE)).value(queryRange(_fromDate,_toDate));
    }
    if(_CustAccount != null)
    {
        ListEnumerator  = _CustAccount.getEnumerator();
        while (ListEnumerator.moveNext())
        {
            queryBuildDataSource.addRange(fieldNum(CustInvoiceJour,ORDERACCOUNT)).value(ListEnumerator.current());
        }
    }
    if(_InvoiceId  != null)
    {
        ListEnumerator  = _InvoiceId.getEnumerator();
        while (ListEnumerator.moveNext())
        {
            queryBuildDataSource.addRange(fieldNum(CustInvoiceJour,InvoiceId)).value(ListEnumerator.current());
        }
    }
    if(_ItemId != null)
    {
        ListEnumerator = _ItemId.getEnumerator();
        while (ListEnumerator.moveNext())
        {
            queryBuildDataSource.addRange(fieldNum(CustInvoicetrans,ItemId)).value(ListEnumerator.current());
        }
    }
    queryRun    = new queryRun(query) ;
    while (queryRun.next())
    {


        _custinvoicejour            =   queryRun.get(tableNum(CustInvoiceJour)) ;
        _custinvoicetrans           =   queryRun.get(tableNum(CustInvoiceTrans)) ;

        select  _ETGSalesShipmentCocoa
            where _ETGSalesShipmentCocoa.RefInvoiceId == _custinvoicetrans.InvoiceId
            && _ETGSalesShipmentCocoa.CustInvoiceTrans == _CustInvoiceTrans.RecId;

        ETG_SalesTableTrade ETG_SalesTableTrade;
        select ETG_SalesTableTrade where ETG_SalesTableTrade.SalesId == _CustInvoiceJour.Salesid;

        ETGCocoaShipmentTmp.clear();
        ETGCocoaShipmentTmp.initValue();
        ETGCocoaShipmentTmp.InvoiceDate                 = _CustInvoiceJour.InvoiceDate;
        ETGCocoaShipmentTmp.InvoiceId                   = _CustInvoiceJour.InvoiceId;
        ETGCocoaShipmentTmp.CustomerCode                = _CustInvoiceJour.OrderAccount;
        ETGCocoaShipmentTmp.CustomerName                = CustTable::find(_CustInvoiceJour.OrderAccount).name();
        ETGCocoaShipmentTmp.ETGReferences               = _ETGSalesShipmentCocoa.ETGReferences;
        ETGCocoaShipmentTmp.CCCReferences               = _ETGSalesShipmentCocoa.CCCReferences;
        ETGCocoaShipmentTmp.ACFContractNumber           = _ETGSalesShipmentCocoa.ACFContractNumber;
        ETGCocoaShipmentTmp.ShippingPeriod              = _ETGSalesShipmentCocoa.ShippingPeriod;
        ETGCocoaShipmentTmp.Customer                    = _ETGSalesShipmentCocoa.Customer;
        ETGCocoaShipmentTmp.Exporter                    = _ETGSalesShipmentCocoa.Exporter;
        ETGCocoaShipmentTmp.ItemNumber                  = _CustInvoiceTrans.ItemId;
        ETGCocoaShipmentTmp.ItemName                    = _CustInvoiceTrans.itemName();
        ETGCocoaShipmentTmp.TheoriticalQuantity         = _ETGSalesShipmentCocoa.TheoriticalQuantity;
        ETGCocoaShipmentTmp.LotsNumber                  = _ETGSalesShipmentCocoa.LotsNumber;
        ETGCocoaShipmentTmp.PalletsLotWeight            = _ETGSalesShipmentCocoa.PalletsLotWeight;
        ETGCocoaShipmentTmp.BillofLadingWeight          = _ETGSalesShipmentCocoa.BillofLadingWeight;
        ETGCocoaShipmentTmp.WeightLoss                  = _ETGSalesShipmentCocoa.WeightLoss;
        ETGCocoaShipmentTmp.WeightLossPer               = _ETGSalesShipmentCocoa.WeightLossPer;
        ETGCocoaShipmentTmp.TransitOrder                = _ETGSalesShipmentCocoa.TransitOrder;
        ETGCocoaShipmentTmp.Port                        = ETG_SalesTableTrade.PortOfLoadingDesc;
        ETGCocoaShipmentTmp.BVApplied                   = _ETGSalesShipmentCocoa.BVApplied;
        ETGCocoaShipmentTmp.BVReceived                  = _ETGSalesShipmentCocoa.BVReceived;
        ETGCocoaShipmentTmp.BVStatus                    = _ETGSalesShipmentCocoa.BVStatus;
        ETGCocoaShipmentTmp.Vessel                      = _ETGSalesShipmentCocoa.Vessel;
       // ETGCocoaShipmentTmp.Remark                     = _ETGSalesShipmentCocoa.BVStatus;
        ETGCocoaShipmentTmp.insert();
    }

}
